func (q *Queries) ListAlertRulesByIDs(ctx context.Context, ids []uuid.UUID) ([]AlertRule, error) {
	rows, err := q.db.Query(ctx, listAlertRulesByIDs, ids)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	items := []AlertRule{}
	for rows.Next() {
		var i AlertRule
		if err := rows.Scan(
			&i.ID,
			&i.Name,
			&i.ClusterID,
			&i.RuleType,
			&i.Configuration,
			&i.Severity,
			&i.Enabled,
			&i.CooldownMinutes,
			&i.CreatedByID,
			&i.CreatedAt,
			&i.UpdatedAt,
			&i.RuleKind,
			&i.AnomalyStddev,
			&i.AnomalyWindowSeconds,
			&i.AnomalyMinSamples,
			&i.AnomalyDirection,
		); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

